def change_fronts(front):
    pts = [(p[0], p[1]) for p in front]
    return sorted(set(pts), key=lambda t: t[0])

def ref_point(list_fronts):
    max_dist = max(p[0] for front in list_fronts for p in front)
    max_co2 = max(p[1] for front in list_fronts for p in front)
    return (max_dist * 1.05, max_co2 * 1.05)

def plot_fronts(list_fronts, ref_pt):
    import matplotlib.pyplot as plt
    plt.figure(figsize=(8, 6))
    for i, front in enumerate(list_fronts):
        pts = change_fronts(front)
        x, y = zip(*pts)
        plt.plot(x, y, marker='o', label=f'Front {i+1}')
    plt.scatter(*ref_pt, color='red', marker='X', s=100, label='Reference Point')
    plt.xlabel('Total Distance')
    plt.ylabel('Total CO2 Emissions')
    plt.title('Pareto Fronts Comparison')
    plt.legend()
    plt.show()

plot_fronts([front1, front2, front3], ref_point([front1, front2, front3]))

def hypervolume(front, ref_pt):
    sorted_front = sorted(front, key=lambda p: p[0])  # just to be sure but fronts are already sorted because of change_fronts()
    hv = 0.0
    prev_y = ref_pt[1]
    for dist, co2 in sorted_front:
        width = ref_pt[0] - dist
        height = prev_y - co2
        hv += width * height
        prev_y = co2
    return hv

print("Hypervolumes:")
for i, front in enumerate([front1, front2, front3], start=1):
    hv = hypervolume(change_fronts(front), ref_point([front1, front2, front3]))
    print(f"Front {i}: Hypervolume = {hv:.2f}")

# Pareto front 2 which was computed with 300 weights has the highest hypervolume => the best pareto front among the three because it covers the largest area in the objective space.